import secrets

G=2
class ZKPEngine:
 @staticmethod
 def generate_statement(h):
  x=int(h,16)%(P-1)
  if x==0:x=99991
  return x,pow(G,x,P)
 @staticmethod
 def compute_commitment():
  r=secrets.randbelow(P-1)+1
  return r,pow(G,r,P)
 @staticmethod
 def assert_proof(Y,y,c,s):
  return pow(G,s,P)==(Y*pow(y,c,P))%P
